/**
 * GEM/Nguyenlh - 15.05.2026:
 * TAM/Sprint 3/Story TAM_46 
 * Calculates TOF (Time of Fill) and assigns OKR category based on day ranges
 */
(function executeRule(current, previous /*null when async*/ ) {

    var recruitmentId = current.u_recruit_id;

    if (recruitmentId) {
        var recruitmentGr = new GlideRecord('x_1763182_talent_0_recruitment_request');

        if (recruitmentGr.get(recruitmentId)) {

            var checkinDate = new GlideDateTime(current.u_checkin_date);
            var startDate = new GlideDateTime(recruitmentGr.u_start_date);

