                var okrCategory = "";

                switch (true) {
                    case (totalDaysElapsed <= 45):
                        okrCategory = "<= 45 days";
                        break;
                    case (totalDaysElapsed <= 50):
                        okrCategory = "<= 50 days";
                        break;
                    case (totalDaysElapsed <= 60):
